// 프린트 -- Invoice List Type Print 
///////////////////////////////////////////////////////////////////////////////////////////
scwin.f_Print = async function () {
  // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
  if (lc_jobgb.getValue() == "") {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, Array("Job Type"));
    lc_jobgb.focus();
    return;
  }
  /*
  if(lc_iogb.getValue().trim()== ""){
      $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, Array("Export/Import"));
      lc_iogb.focus();
      return;
  }	
  */
  if (ed_bldtfrom.getValue().trim() == '' || ed_bldtto.getValue().trim() == '') {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_002, Array("ETD"));
    ed_bldtfrom.focus();
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ed_bldtfrom.getValue().trim(), ed_bldtto.getValue().trim(), false)) {
    $c.gus.cfAlertMsg($p, E_MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
    return;
  }
  let odiParam = {};
  let reportFile = "";
  let odiName = "";
  let mode = "";
  if (lc_jobgb.getValue() == "S") {
    reportFile = "/il/acc/ac_102_01_01_01.ozr";
    odiName = "ac_102_01_01";
  } else if (lc_jobgb.getValue() == "A") {
    reportFile = "/il/acc/ac_102_01_01_01_air.ozr";
    odiName = "ac_102_01_01_air";
  } else {
    reportFile = "/il/acc/ac_102_01_01_01_trans.ozr";
    odiName = "ac_102_01_01_trans";
  }
  if (chb_pre.getValue() == "T") {
    mode = "preview";
  }
  if (chb_sav.getValue() == "T") {
    mode = "print";
  }
  if (lc_jobgb.getValue() == "S") {
    let slipParam = "";
    if (ed_slipNo.getValue().trim() != null && ed_slipNo.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo.getValue().trim() + ")";
    }
    if (ed_slipNo2.getValue().trim() != null && ed_slipNo2.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo2.getValue().trim() + ")";
    }
    if (ed_slipNo3.getValue().trim() != null && ed_slipNo3.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo3.getValue().trim() + ")";
    }
    if (ed_slipNo4.getValue().trim() != null && ed_slipNo4.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo4.getValue().trim() + ")";
    }
    odiParam = {
      //odiParam.add("KCOMCD", hid_kcomcd.value.trim());
      "KCOMCD": scwin.hid_kcomcd,
      "IOGB": lc_iogb.getValue().trim(),
      "SEAAIR": lc_jobgb.getValue().trim(),
      "FROM_DT": ed_bldtfrom.getValue().trim(),
      "TO_DT": ed_bldtto.getValue().trim(),
      "BILG_CLNT_NO": ed_cncd.getValue().trim(),
      "BILG_LODEPT_CD": ed_dept.getValue().trim(),
      "CNNM": txt_cnnm.getValue().trim(),
      //한국앤컴퍼니
      "ANNM": txt_annm.getValue().trim(),
      //담당자팝업
      "ADMINPIC": txt_adminPicNm.getValue().trim(),
      //업무담당자팝업
      //odiParam.add("LOBRANCD", hid_lobranCd.value.trim());  다시확인필요
      "LOBRANCD": ed_adminPic.getValue().trim(),
      //부서(ed_adminPic),B/L담당자(cnd_ed_picNo)

      "CERTI_NO": ed_certiNo.getValue().trim(),
      "PRTN_GRP_NO": ed_prtnGrpNo.getValue().trim(),
      "SLIP_NO": slipParam.substring(1),
      "PRINT_DT": lc_printDt.getValue().trim(),
      "PIC": cnd_ed_picNo.getValue().trim()
    };
  } else if (lc_jobgb.getValue() == "A") {
    let slipParam = "";
    if (ed_slipNo.getValue().trim() != null && ed_slipNo.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo.getValue().trim() + ")";
    }
    if (ed_slipNo2.getValue().trim() != null && ed_slipNo2.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo2.getValue().trim() + ")";
    }
    if (ed_slipNo3.getValue().trim() != null && ed_slipNo3.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo3.getValue().trim() + ")";
    }
    if (ed_slipNo4.getValue().trim() != null && ed_slipNo4.getValue().trim() != "") {
      slipParam = slipParam + ",TO_CHAR(" + ed_slipNo4.getValue().trim() + ")";
    }
    odiParam = {
      //odiParam.add("KCOMCD", hid_kcomcd.value.trim());
      "KCOMCD": scwin.hid_kcomcd,
      "IOGB": lc_iogb.getValue().trim(),
      "SEAAIR": lc_jobgb.getValue().trim(),
      "FROM_DT": ed_bldtfrom.getValue().trim(),
      "TO_DT": ed_bldtto.getValue().trim(),
      "CUST": ed_cncd.getValue().trim(),
      "DEPT": ed_dept.getValue().trim(),
      "CERTI_NO": ed_certiNo.getValue().trim(),
      "PRTN_GRP_NO": ed_prtnGrpNo.getValue().trim(),
      "SLIP_NO": slipParam.substring(1),
      "PRINT_DT": lc_printDt.getValue().trim(),
      "PIC": cnd_ed_picNo.getValue().trim()
    };
  } else {
    odiParam = {
      //odiParam.add("KCOMCD", hid_kcomcd.value.trim());
      "KCOMCD": scwin.hid_kcomcd,
      "IOGB": lc_iogb.getValue().trim(),
      "SEAAIR": lc_jobgb.getValue().trim(),
      "FROM_DT": ed_bldtfrom.getValue().trim(),
      "TO_DT": ed_bldtto.getValue().trim(),
      "CUST": ed_cncd.getValue().trim(),
      "DEPT": ed_dept.getValue().trim(),
      "CERTI_NO": ed_certiNo.getValue().trim(),
      "PRTN_GRP_NO": ed_prtnGrpNo.getValue().trim(),
      "SLIP_NO": ed_slipNo.getValue().trim(),
      "PRINT_DT": lc_printDt.getValue().trim(),
      "TRANSTYP": lc_transTyp.getValue().trim()
    };
  }

  // 선택한 열 체크
  let check = "";
  if ("TYPE3" == scwin.processType) {
    for (var i = 0; i < ds_InvoiceExcelType3.getRowCount(); i++) {
      if (ds_InvoiceExcelType3.getCellData(i, "choice") == "T") {
        check += ",TO_CHAR(" + ds_InvoiceExcelType3.getCellData(i, "prtnGrpNo") + ")";
      }
    }
    // odiParam.add("PRTN_GRP_NO2", check.substring(1));
    //check.substring(1)의미 : "S12345"	"12345"	첫 글자 'S' 제거
    odiParam["PRTN_GRP_NO2"] = check.substring(1);
  }
  let choiceHouseNo = "";
  if ("TYPE11" == scwin.processType) {
    for (var i = 0; i < ds_InvoiceExcelType11.getRowCount(); i++) {
      if (ds_InvoiceExcelType11.getCellData(i, "chk") == "T") {
        if (lc_jobgb.getValue().trim() + lc_iogb.getValue().trim() != ds_InvoiceExcelType11.getCellData(i, "seaAir")) {
          alert("선택 된 Invoice와 Job Type, 수출입 구분이 일치하지 않습니다.");
          return false;
        }
        choiceHouseNo = choiceHouseNo + ",TO_CHAR(" + ds_InvoiceExcelType11.getCellData(i, "odrNo").substring(3) + ")"; // 오더번호
      }
    }
    // odiParam.add("ODR_NO", choiceHouseNo.substring(1));
    odiParam["ODR_NO"] = choiceHouseNo.substring(1);
    // 		alert(choiceHouseNo.substring(1));
  }
  let data = {
    odiName: odiName,
    reportName: reportFile,
    odiParam: odiParam,
    viewerParam: {
      "useprogressbar": false // 프로그레스바 쓸지 말지
      //"mode": mode
      //"mode": "silent"
    },
    formParam: {}
  };
  console.log("scwin.memJson::", scwin.memJson);
  console.log("invoice print data::", data);
  await scwin.openPopup(data);
};
