scwin.udc_clntNo_onblurNameEvent = function (e) {
  if (!txt_cnnm.realValue) {
    txt_cnnm.setValue(txt_cnnm.originalValue);
    return;
  }
  // 3. 값이 비어있으면 종료 (관련 코드 초기화 필요 시 추가)
  if (txt_cnnm.getValue() == "") {
    return;
  } else {
    // 1. 기준 업체명 (기존에 로드되어 있던 정식 명칭)
    let masterValue = txt_cnnm.originalValue;
    // 2. 현재 입력창에 보이는 실제 값 (realValue)
    let inputVal = (txt_cnnm.realValue || "").trim();
    // 5. 매칭 체크 (대소문자 무시, 한글 포함)
    // masterValue가 inputVal로 시작하는지 확인
    let isMatch = masterValue.toUpperCase().startsWith(inputVal.toUpperCase());
    if (isMatch) {
      // [TRUE] 일치할 경우: "aa" -> "AA LOGISTICS CO., LTD." 대문자 정식명칭 유지
      txt_cnnm.setValue(masterValue);
    } else {
      udc_clntNo.ilCommonPopUp(scwin.udc_clntNo_onblurNameEvent_callBackFunc, "" //pCode
      , txt_cnnm.getValue() //pName
      , "T" //pWinCloseTF // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
      , "5" //pDispCnt
      , "Customer" //pTitle
      , null //pWidth
      , null //pHidden
      , null //pWhere
      , "500" // pW
      , "500" //pH
      , null //pTop
      , null //pLeft
      , null //pExistTF
      , "F" //pAllSearchTF
      , null //pWtitleSearch
      , null //pNoDataCloseTF
      , null //tmpDataSet
      );
    }
  }
  ;
};

