scwin.gr_InvoiceType3_s_oncellclick = function (rowIndex, columnIndex, columnId) {
  if (ds_InvoiceExcelType3.getRowCount() == 0) {
    return;
  }
  switch (columnId) {
    case "choice":
      if (ds_InvoiceExcelType3.getCellData(rowIndex, "choice") == "T") {
        for (let i = 0; i < ds_InvoiceExcelType3.getRowCount(); i++) {
          if (ds_InvoiceExcelType3.getCellData(i, "prtnGrpNo") == ds_InvoiceExcelType3.getCellData(rowIndex, "prtnGrpNo")) {
            ds_InvoiceExcelType3.setCellData(i, "choice", "T");
          }
        }
      }
      if (ds_InvoiceExcelType3.getCellData(rowIndex, "choice") == "F") {
        for (let i = 0; i < ds_InvoiceExcelType3.getRowCount(); i++) {
          if (ds_InvoiceExcelType3.getCellData(i, "prtnGrpNo") == ds_InvoiceExcelType3.getCellData(rowIndex, "prtnGrpNo")) {
            ds_InvoiceExcelType3.setCellData(i, "choice", "F");
          }
        }
      }
      break;
    default:
      break;
  }
};
